module SR_latch(input Invalid_S, input R, output reg Q, output reg Qn);  
    always @(Invalid_S or R) begin  
        if (Invalid_S && R) begin  
            // Invalid state, do nothing or maintain previous state  
        end else if (Invalid_S) begin  
            Q <= 1;  
            Qn <= 0;  
        end else if (R) begin  
            Q <= 0;  
            Qn <= 1;  
        end  
    end  
endmodule
